import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature value */
  temperature: number;
  /** Weather condition text (e.g., Sunny, Cloudy) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed value */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast data */
  forecast: ForecastItem[];
}

/**
 * A comprehensive weather information card featuring current conditions,
 * key metrics (humidity, wind), and a 5-day forecast strip.
 */
const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = [],
}) => {
  return (
    <Card
      style={{
        padding: 'var(--ggui-spacing-6)',
        borderRadius: 'var(--ggui-radius-xl)',
        boxShadow: 'var(--ggui-shadow-md)',
        backgroundColor: 'var(--ggui-color-surface)',
      }}
    >
      <Stack direction="vertical" gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header Section */}
        <Stack direction="vertical" gap="var(--ggui-spacing-1)" align="start">
          <Heading level={2} style={{ color: 'var(--ggui-color-on-surface)' }}>
            {city}
          </Heading>
          <Text
            variant="body-large"
            style={{ color: 'var(--ggui-color-on-surface-variant)' }}
          >
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Section */}
        <Stack direction="horizontal" align="start" gap="var(--ggui-spacing-1)">
          <Text
            style={{
              fontSize: 'var(--ggui-font-size-4xl)',
              fontWeight: 'var(--ggui-font-weight-bold)',
              color: 'var(--ggui-color-on-surface)',
              lineHeight: '1',
            }}
          >
            {temperature}°
          </Text>
          <Text
            style={{
              fontSize: 'var(--ggui-font-size-xl)',
              fontWeight: 'var(--ggui-font-weight-medium)',
              color: 'var(--ggui-color-primary)',
              marginTop: 'var(--ggui-spacing-1)',
            }}
          >
            {unit}
          </Text>
        </Stack>

        {/* Weather Details Section */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-8)" align="center">
          <Stack direction="vertical" gap="var(--ggui-spacing-1)">
            <Text
              variant="label-small"
              style={{
                color: 'var(--ggui-color-on-surface-variant)',
                textTransform: 'uppercase',
              }}
            >
              Humidity
            </Text>
            <Text
              style={{
                fontWeight: 'var(--ggui-font-weight-semibold)',
                color: 'var(--ggui-color-on-surface)',
              }}
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap="var(--ggui-spacing-1)">
            <Text
              variant="label-small"
              style={{
                color: 'var(--ggui-color-on-surface-variant)',
                textTransform: 'uppercase',
              }}
            >
              Wind
            </Text>
            <Text
              style={{
                fontWeight: 'var(--ggui-font-weight-semibold)',
                color: 'var(--ggui-color-on-surface)',
              }}
            >
              {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Stack>

        <Divider />

        {/* Forecast Strip Section */}
        <Box
          style={{
            padding: 'var(--ggui-spacing-4)',
            backgroundColor: 'var(--ggui-color-surface-variant)',
            borderRadius: 'var(--ggui-radius-lg)',
            overflow: 'hidden',
          }}
        >
          <Stack direction="horizontal" justify="between" align="center">
            {forecast.map((item, index) => (
              <Stack
                key={`${item.day}-${index}`}
                direction="vertical"
                gap="var(--ggui-spacing-2)"
                align="center"
              >
                <Text
                  variant="body-small"
                  style={{
                    fontWeight: 'var(--ggui-font-weight-medium)',
                    color: 'var(--ggui-color-on-surface-variant)',
                  }}
                >
                  {item.day}
                </Text>

                <Text
                  style={{ fontSize: 'var(--ggui-font-size-xl)' }}
                >
                  {item.icon}
                </Text>

                <Stack direction="horizontal" gap="var(--ggui-spacing-1)">
                  <Text
                    style={{
                      fontWeight: 'var(--ggui-font-weight-bold)',
                      fontSize: 'var(--ggui-font-size-xs)',
                      color: 'var(--ggui-color-on-surface)',
                    }}
                  >
                    {item.high}°
                  </Text>
                  <Text
                    style={{
                      fontSize: 'var(--ggui-font-size-xs)',
                      color: 'var(--ggui-color-on-surface-variant)',
                    }}
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
};

export default WeatherCard;
